const { MeliStatsD } = require('@meli/statsd');
const { config } = require('frontend-config');
const env = require('frontend-env');

const { deprecationWrapper } = require('./deprecation-logger');

const { globalTags, suffix } = config.get('statsd') || {};

const statsdOptions = {
  prefix: `application.${env.APPLICATION || env.npm_package_name}.`,
  suffix,
  globalTags,
};

const statsDClient = new MeliStatsD(statsdOptions);

module.exports = deprecationWrapper(statsDClient);
